/**
 * Maritime Sea Lane Routing Engine
 *
 * Primary path: looks up pre-computed realistic maritime routes from
 * /maritime_routes.json (generated by scripts/generate_maritime_routes.py
 * using the searoute / Marnet graph library).
 *
 * Fallback path: if the JSON is not yet loaded or a port pair is missing,
 * uses the original port-cluster gate system to keep lines over water.
 *
 * The exported maritimeRoute() function signature is unchanged -- RouteMap.tsx
 * calls it exactly as before.
 */

export type LatLon = [number, number]; // [lat, lon]

// ---------------------------------------------------------------------------
// Pre-computed route cache
// Populated once by loadMaritimeRoutes() on first call.
// ---------------------------------------------------------------------------
let routeCache: Record<string, LatLon[]> | null = null;
let loadPromise: Promise<void> | null = null;

async function loadMaritimeRoutes(): Promise<void> {
  if (routeCache !== null) return;
  if (loadPromise) return loadPromise;

  loadPromise = (async () => {
    try {
      const res = await fetch("/maritime_routes.json");
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      const data: Record<string, [number, number][]> = await res.json();
      routeCache = data as Record<string, LatLon[]>;
    } catch {
      // File not yet generated -- use empty cache, fallback will handle routing
      routeCache = {};
    }
  })();

  return loadPromise;
}

// Kick off the load immediately when this module is imported
loadMaritimeRoutes();

