// ---------------------------------------------------------------------------
// Fallback routing engine (gate/cluster system)
// ---------------------------------------------------------------------------
function getCluster(portName: string): string | null {
  return PORT_CLUSTERS[portName.toLowerCase()] ?? null;
}

function gateKey(a: string, b: string): string {
  return a < b ? `${a}|${b}` : `${b}|${a}`;
}

function gateFallback(
  fromName: string,
  fromCoord: LatLon,
  toName: string,
  toCoord: LatLon
): LatLon[] {
  const fromCluster = getCluster(fromName);
  const toCluster = getCluster(toName);

  if (!fromCluster || !toCluster || fromCluster === toCluster) {
    return [fromCoord, toCoord];
  }

  const key = gateKey(fromCluster, toCluster);
  const gates = SEA_GATES[key];

  if (!gates || gates.length === 0) {
    return [fromCoord, toCoord];
  }

  const reversed = fromCluster > toCluster;
  const orderedGates = reversed ? [...gates].reverse() : gates;

  return [fromCoord, ...orderedGates, toCoord];
}

// ---------------------------------------------------------------------------
// Public API -- same signature as before, RouteMap.tsx is unchanged
// ---------------------------------------------------------------------------

/**
 * Returns the full list of [lat, lon] waypoints (including start and end)
 * that keep the route over water.
 *
 * Uses pre-computed searoute/Marnet data when available.
 * Falls back to the gate/cluster system for unknown or not-yet-computed pairs.
 */
export function maritimeRoute(
  fromName: string,
  fromCoord: LatLon,
  toName: string,
  toCoord: LatLon
): LatLon[] {
  // Build the lookup key (alphabetical order, same as the Python script)
  const key = fromName < toName
    ? `${fromName}|${toName}`
    : `${toName}|${fromName}`;

  if (routeCache && routeCache[key]) {
    const waypoints = routeCache[key];
    // The JSON stores waypoints in alphabetical-key order.
    // If fromName comes after toName alphabetically, the route is stored
    // in reverse -- flip it so it runs from -> to.
    if (fromName > toName) {
      return [...waypoints].reverse() as LatLon[];
    }
    return waypoints as LatLon[];
  }

  // Cache not loaded yet or pair missing -- use gate fallback
  return gateFallback(fromName, fromCoord, toName, toCoord);
}

/**
 * Returns a Promise that resolves once the maritime routes JSON has been
 * fetched and cached. Call this before plotting routes if you want to
 * guarantee the pre-computed data is available.
 */
export async function ensureMaritimeRoutesLoaded(): Promise<void> {
  return loadMaritimeRoutes();
}
